      for(i=0;i<q;i++){
        int x=in.nextInt()-1;
        arr[x]++;

      }
      for(i=0;i<n;i++){
        sum+=arr[i];
      }
      for(i=0;i<n;i++){
        if((long)k-sum+(long)arr[i]>0){
          w.println("Yes");
        }else{
          w.println("No");
        }
      }
        w.close();
    }

}

