        FastScanner fs = new FastScanner();
        long N = fs.nextLong();

        int ans = Long.toString(N).length();

        for (long i = 1; i*i <= N; ++i) {
            if (N % i != 0) continue;
            long num = N / i;

            int tmp = Math.max(Long.toString(i).length(), Long.toString(num).length());

            if (ans > tmp) ans = tmp;
        }

        System.out.println(ans);
    }
