            while (isSpaceChar(c))
                c = read();

            int sgn = 1;

            if (c == '-') {
                sgn = -1;
                c = read();
            }

            double res = 0;

            while (!isSpaceChar(c) && c != '.') {

                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());

                if (c < '0' || c > '9')
