				System.out.println(1);
				return;
			} else {
				System.out.println(0);
				return;
			}
		}

		if(C == D) {
			long x = 0;
			if(A % C != 0) {
				x = (B - (A / C + 1) * C) / C + 1;
			} else {
				x = (B - A) / C + 1;
			}
			System.out.println(B - A + 1 - x);
			return;
		}


		if(A % C != 0) {
			if(A > C) {
				c = (B - (A / C + 1) * C) / C + 1;
			} else {
				if(C <= B) {
					c = (B - C) / C + 1;
				} else {
					c = 0;
				}
			}
		} else {
			if(A > C) {
				c = (B - A) / C + 1;
			} else {
				if(C <= B) {
					c = (B - C) / C + 1;
				} else {
					c = 0;
				}
			}
		}

		if(A % D != 0) {
			if(A > D) {
				d = (B - (A / D + 1) * D) / D + 1;
			} else {
				if(D <= B) {
					d = (B - D) / D + 1;
				} else {
					d = 0;
				}
			}
		} else {
			if(A > D) {
				d = (B - A) / D + 1;
			} else {
				if(D <= B) {
					d = (B - D) / D + 1;
				} else {
					d = 0;
				}
			}
		}

		if(A % koub != 0) {
			if(A > koub) {
				cd = (B - (A / koub + 1) * koub) / koub + 1;
			} else {
				if(koub <= B) {
					cd = (B - koub) / koub + 1;
				} else {
					cd = 0;
				}
			}
		} else {
			if(A > koub) {
				cd = (B - A) / koub + 1;
