class AtCoder {


    final int H;
    final int N;
    final int[] A;

    AtCoder(FastScanner sc) {
        H = sc.nextInt();
        N = sc.nextInt();
        A = new int[N];
        for (int i = 0; i < A.length; i++) {
            A[i] = sc.nextInt();
        }

    }

    void solve(PrintWriter out) {
        int HP = H;
        for (int i = 0; i < A.length; i++) {
            HP -= A[i];
            if (HP > 0) {
                continue;
            } else {
                out.println("Yes");
                break;
            }
        }

        if (HP > 0) {
            out.println("No");
        }
    }
}


