    private static int f(int sum, int k) {
        if (sum < 0) return 0;
        int ans = 0;
        for (int i = 0; i <= k; i++) {
            if (sum - i <= k && sum - i >= 0) ans++;
        }
        return ans;
    }

    private static int g(int sum, int k) {
        int ans = 0;
        for (int i = 0; i <= k; i++) {
            ans += f(sum - i, k);
        }
        return ans;
    }

