		for (int i = 0; i < n; i++) {
			a[i] = sc.nextInt();
		}
		boolean flag = true;
		int count = 0;
		while (flag) {
			flag = false;
			for (int i = n - 1; i > 0; i--) {
				if (a[i] < a[i - 1]) {
					int tmp = a[i];
