    static int solve(int cur, int[] a, int k)
    {
        int n = a.length;
        if(cur >= n) return Integer.MAX_VALUE;
        if(cur == n-1)  return 0;
        if(minCostFrom[cur] != -1)  return minCostFrom[cur];
        int step = Integer.MAX_VALUE;
        for(int i = 1; i <= k; i++)
        {
            int now = Integer.MAX_VALUE;
            if(cur+i < n)
                now = Math.abs(a[cur]-a[cur+i]) + solve(cur+i, a, k);
            step = Math.min(now, step);
        }
        return minCostFrom[cur] = step;
    }

